def has_block_children(element: Tag) -> bool:
    for child in element.children:
        if isinstance(child, Tag) and child.name in BLOCK_TAGS:
            return True
    return False

def traverse(tag: Tag, parent_id: Optional[str]=None):
    if not isinstance(tag, Tag):
        return
    if tag.name == 'table':
        table_docs = self._process_table_element(tag, filename, parent_id)
        docs.extend(table_docs)
        return
    is_content_unit = tag.name in {'p', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6', 'li'} or (tag.name in BLOCK_TAGS and (not has_block_children(tag)))
    if is_content_unit:
        text_content = tag.get_text(' ', strip=True)
        if text_content and len(text_content) > 5:
            node_id = str(uuid.uuid4())
            if len(text_content) > 200:
                splits = self.text_splitter_small.split_text(text_content)
            else:
                splits = [text_content]
            for i, split in enumerate(splits):
                docs.append(Document(page_content=split, metadata={'id': f'{node_id}_{i}', 'file_name': filename, 'html_tag': tag.name, 'parent_ref': parent_id, 'page_number': 1}))
        return
    for child in tag.children:
        if isinstance(child, Tag):
            traverse(child, parent_id)

def extract_pdf_content(self, pdf_path, output_folder='extracted_data'):
    doc = pymupdf.open('a.pdf')
    for page in doc:
        text = page.get_text().encode('utf8')
        text_splitter = RecursiveCharacterTextSplitter(chunk_size=200, chunk_overlap=60, length_function=len, separators=['\n\n', '\n', ' ', ''])
        chunks = text_splitter.split_text(text)
        for chunk in chunks:
            self.g.add_node()

def process_image(self, doc):
