def create_g_visual(G, dest_path=None, ds=True):
    """
    Build pyvis Network from graph G with custom styles.
    ds=True: datastore format (nodes with graph_item, edges as special nodes).
    ds=False: direct format (G.nodes + G.edges, e.g. from StructInspector).
    """
    print('create_g_visual G:', G, file=sys.stderr)
    try:
        new_G = nx.MultiGraph()
        if ds:
            for nid, attrs in G.nodes(data=True):
                if attrs.get('graph_item') == 'node':
                    ntype = attrs.get('type', 'NODE')
                    new_G.add_node(nid, **_style_node(ntype, nid))
            for nid, attrs in G.nodes(data=True):
                if attrs.get('graph_item') == 'edge':
                    src, trgt = (attrs.get('src'), attrs.get('trgt'))
                    if src and trgt and new_G.has_node(src) and new_G.has_node(trgt):
                        rel = attrs.get('rel', 'edge')
                        new_G.add_edge(src, trgt, color=_rel_color(rel), title=rel)
        else:
            for nid, attrs in G.nodes(data=True):
                ntype = attrs.get('type', 'NODE')
                new_G.add_node(nid, **_style_node(ntype, nid))
            for src, trgt, attrs in G.edges(data=True):
                if new_G.has_node(src) and new_G.has_node(trgt):
                    rel = attrs.get('rel', 'link')
                    new_G.add_edge(src, trgt, color=_rel_color(rel), width=1.2, title=rel)
        options = '\n            const options = {\n              "nodes": {\n                "borderWidth": 2,\n                "borderWidthSelected": 4,\n                "font": { "size": 14, "face": "Segoe UI", "color": "#ffffff" },\n                "shadow": { "enabled": true, "color": "rgba(0,0,0,0.2)", "size": 10, "x": 2, "y": 2 }\n              },\n              "edges": {\n                "smooth": { "type": "continuous", "roundness": 0.5 },\n                "font": { "size": 11, "color": "#cccccc" }\n              },\n              "physics": {\n                "barnesHut": {\n                  "gravitationalConstant": -3000,\n                  "centralGravity": 0.1,\n                  "springLength": 150,\n                  "springConstant": 0.04,\n                  "damping": 0.09\n                }\n              }\n            }\n            '
        net = Network(notebook=False, cdn_resources='in_line', height='1000px', width='100%', bgcolor='#1a1a2e', font_color='white')
        net.barnes_hut()
        net.toggle_physics(True)
        net.set_options(options)
        net.from_nx(new_G)
        net.html = net.generate_html()
        if dest_path is not None:
            parent = os.path.dirname(dest_path)
            if parent:
                os.makedirs(parent, exist_ok=True)
            with open(dest_path, 'w', encoding='utf-8') as f:
                f.write(net.html)
            print('html created and saved under:', dest_path, file=sys.stderr)
        else:
            return net.html
    except Exception as e:
        print('Err create_g_visual:', e, file=sys.stderr)

def flatten_payload(payload: dict) -> dict:
    """
    Flatten nested payload {auth: {...}, data: {...}} to top-level dict.
    All keys from auth and data become top-level kwargs for handler methods.
    """
    if not isinstance(payload, dict):
        return {}
    auth = payload.get('auth') or {}
    data = payload.get('data') or {}
    if not isinstance(auth, dict):
        auth = {}
    if not isinstance(data, dict):
        data = {}
    return {**auth, **data}

def invoke(*args, **kwargs):
    mod = importlib.import_module(module_name)
    if class_name and has_self:
        cls = getattr(mod, class_name)
        instance = cls()
        func = getattr(instance, method_name)
        if args and len(args) == 1 and isinstance(args[0], dict) and (not kwargs):
            return func(**flatten_payload(args[0]))
        return func(*args, **kwargs)
    else:
        func = getattr(mod, method_name)
        if args and len(args) == 1 and isinstance(args[0], dict) and (not kwargs):
            return func(**flatten_payload(args[0]))
        return func(*args, **kwargs)

def process_method_params(self, node, method_id, return_key):
    filtered_args = []
    return_key = return_key.strip()
    for arg in node.args.args:
        try:
            if arg.arg == 'self':
                continue
            param_name = arg.arg
            param_type = _get_type_name(arg.annotation)
            print(f'ADD PARAM: {param_name}', file=sys.stderr)
            self.g.add_node(attrs=dict(id=param_name, type='PARAM', param_type=param_type))
            self.g.add_edge(src=method_id, trgt=param_name, attrs=dict(rel='requires_param', type=param_type, trgt_layer='PARAM', src_layer='METHOD'))
            if not self.g.G.has_edge(self.module_name, param_name):
                self.g.add_edge(src=self.module_name, trgt=param_name, attrs=dict(rel='requires_param', trgt_layer='PARAM', src_layer='MODULE'))
            filtered_args.append(arg.arg)
        except Exception as e:
            print('Err node.args.args', e, file=sys.stderr)
    if return_key:
        self.g.add_node(attrs=dict(id=return_key, type='PARAM'))
        self.g.add_edge(src=method_id, trgt=return_key, attrs=dict(rel='returns_param', trgt_layer='PARAM', src_layer='METHOD'))
        if not self.g.G.has_edge(self.module_name, return_key):
            self.g.add_edge(src=self.module_name, trgt=return_key.strip(), attrs=dict(rel='returns_param', trgt_layer='PARAM', src_layer='MODULE'))
    print('process_method_params... done -> filtered_args', filtered_args, file=sys.stderr)

def extract_return_statement_expression(self, method_node: ast.FunctionDef) -> Optional[str]:
    """
        Extracts the name/identifier of the returned expression, stripped of whitespace.
        """
    for node in ast.walk(method_node):
        try:
            if isinstance(node, ast.Return) and node.value is not None:
                return ast.unparse(node.value).strip()
        except Exception as e:
            print(f'Err extract_return_statement_expression: {e}')
    return ''

def visit_Assign(self, node: ast.Assign):
    """Identifies class variables and creates CLASS_VAR nodes."""
    if not self.current_class:
        return
    for target in node.targets:
        try:
            if isinstance(target, ast.Name):
                var_name = target.id
                value_type = 'Unknown'
                var_id = f'{self.current_class}.{var_name}'
                self.g.add_node(dict(id=var_id, type='CLASS_VAR', name=var_name, inferred_type=value_type))
                self.g.add_edge(src=self.current_class, trgt=var_id, attrs=dict(rel='has_var', trgt_layer='CLASS_VAR', src_layer='CLASS'))
        except Exception as e:
            print('Err Assign:', e, file=sys.stderr)

def convert_module_to_graph(self, code_content: str, module_name: str):
    """
        Parses code content, runs the inspector, and returns the graph.
        Takes code as a string input, as required by ast.parse.
        """
    self.module_name = module_name
    print('ADD MODULE:', module_name, file=sys.stderr)
    self.g.add_node(attrs=dict(id=module_name, type='MODULE', name=module_name))
    try:
        if not code_content.strip():
            return {'Error': 'Input code content is empty.'}
        tree = ast.parse(code_content)
        self.visit(tree)
        _UsageLinker(self.g, module_name).visit(tree)
    except Exception as e:
        print(f'Error processing code structure for {module_name}: {e}', file=sys.stderr)

def visit_Call(self, node: ast.Call):
    if not self.current_method_id:
        self.generic_visit(node)
        return
    callee = self._resolve_callee(node)
    if callee:
        self._add_link(self.current_method_id, callee, 'calls', 'METHOD', 'METHOD')
        for arg in node.args:
            if isinstance(arg, ast.Name) and arg.id in self.param_names:
                self._add_link(arg.id, callee, 'passes_to', 'PARAM', 'METHOD')
    self.generic_visit(node)

def add_edge(self, src=None, trgt=None, attrs: dict=None, **kwargs):
    attrs = attrs or {}
    src = src or attrs.get('src')
    trgt = trgt or attrs.get('trgt')
    src_layer = (attrs.get('src_layer') or 'NODE').upper().replace(' ', '_')
    trgt_layer = (attrs.get('trgt_layer') or 'NODE').upper().replace(' ', '_')
    rel = (attrs.get('rel') or 'link').lower().replace(' ', '_')
    if src and trgt:
        edge_attrs = {k: v for k, v in attrs.items() if k not in ('src', 'trgt', 'src_layer', 'trgt_layer', 'rel')}
        self.G.add_edge(src, trgt, rel=rel, src_layer=src_layer, trgt_layer=trgt_layer, **edge_attrs)
